async def add_extra():  
    async with AsyncSessionLocal() as session:  
        existing = set((await session.scalars(select(Product.name))).all())  
        rows = [Product(**payload) for payload in EXTRA_PRODUCTS if payload['name'] not in existing]  
        if rows:  
            session.add_all(rows)  
            await session.commit()  
            for index, row in enumerate(rows):  
                session.add_all(build_snapshots(row.id, row.guide_price, index + 40))  
            await session.commit()  
    await engine.dispose()  
  
if __name__ == '__main__':  
    asyncio.run(add_extra()) 
